/* Layouts reais com Flexbox */

.header {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

@media (min-width: 768px) {
  .header {
    flex-direction: row;
    align-items: center;
    justify-content: space-between;
  }
}

.toolbar {
  display: flex;
  flex-wrap: wrap;
  gap: 12px;
  align-items: center;
}

.search {
  flex: 1;
  min-width: 220px;
}

.cards {
  display: flex;
  flex-wrap: wrap;
  gap: 16px;
}

.card {
  flex: 1 1 260px;
  padding: 16px;
  border: 1px solid rgba(17, 24, 39, 0.12);
  border-radius: 14px;
}

.media {
  display: flex;
  gap: 12px;
  align-items: flex-start;
}

.media-icon {
  width: 44px;
  height: 44px;
  flex: 0 0 44px;
}

.media-body {
  flex: 1;
}

.push-right {
  margin-left: auto;
}
